import{_ as e,o as t,c as s,O as n}from"./chunks/framework.0d5b6918.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/product/script-risk-levels.md","filePath":"en/product/script-risk-levels.md","lastUpdated":1776439080000}'),i={name:"en/product/script-risk-levels.md"};function r(l,a,o,c,d,p){return t(),s("div",null,a[0]||(a[0]=[n('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Risk Control</p><h1>Script Risk Levels</h1><div class="brand-hero__panel"><span class="brand-pill">Risk Standard</span><strong>ExecFabric currently fixes script / Skill risk levels to <code>low / medium / high</code>. These levels decide how conservative the platform should be during onboarding, confirmation, authorization, and execution.</strong><p>This is not marketing wording. It is a concrete governance rule for scripts, file handling, local execution, and operations work.</p></div><p class="brand-lead"> A risk level does not answer whether a capability is useful. It answers <strong>how large the impact area is once it runs, how reversible it is, and whether manual confirmation should remain stricter</strong>. </p><div class="brand-chip-list"><span class="brand-chip">low</span><span class="brand-chip">medium</span><span class="brand-chip">high</span><span class="brand-chip">manual confirmation</span><span class="brand-chip">authorization boundary</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="./cli.html">View CLI metadata rules</a><a class="cta-button" href="/en/contact.html#lead-form">Discuss onboarding boundaries</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECFABRIC // RISK LEVELS</span><span>DOC 08</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">low</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;read_only / reorganize / copy_out&#39;</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">medium</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;real_data / local_run / external_access&#39;</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">high</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;deploy / rollback / overwrite / delete&#39;</span></span></div><div class="matrix-panel__callout">DECLARED / GOVERNED / TRACEABLE</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">default</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">medium</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">levels</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">3</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">confirm</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">kept</span></span></div></div></div></section><section class="brand-card"><p class="brand-kicker">Current Rule</p><h2>How the current risk level is derived</h2><ul class="brand-list"><li>Registered directories, official script packages, and tenant initialization capabilities first read explicit <code>risk_level</code> metadata.</li><li>The CLI scanner reads <code>@risk</code> / <code>risk_level</code> from script comments, docstrings, or sidecar metadata.</li><li>The web upload registration path currently reads the same markers from the script header or docstring.</li><li>If no explicit level is declared, the current default is <code>medium</code>, not <code>low</code>.</li></ul></section><section class="brand-card"><p class="brand-kicker">Three Levels</p><h2>The three-level standard</h2><table><thead><tr><th>Level</th><th>Typical actions</th><th>Examples</th><th>Governance guidance</th></tr></thead><tbody><tr><td><code>low</code></td><td>Read-only, analysis, reorganization, or copy generation without directly changing production state</td><td>Directory cleanup, batch image renaming, log error extraction, text deduplication, CSV profiling</td><td>Manual confirmation can still stay on by default. Relax only after the input boundary is clearly defined.</td></tr><tr><td><code>medium</code></td><td>Touches real data, the local environment, external systems, or batch outputs, but usually does not directly change production state</td><td>Pre-release checks, local Agent execution, crawlers, internal data aggregation</td><td>Keep manual confirmation by default and limit role visibility, timeout, and invocation scope.</td></tr><tr><td><code>high</code></td><td>Deployment, rollback, deletion, overwrite, remote commands, or production-environment changes with higher impact</td><td>Remote Compose deployment, remote Compose rollback, irreversible batch writes</td><td>Do not open as default AI auto-run. Keep manual confirmation and stricter authorization boundaries.</td></tr></tbody></table></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Why Many Look Low</p><h2>Why many public examples currently look lower risk</h2><ul class="brand-list"><li>The first public samples focus on file reorganization, text cleanup, log extraction, and demo capabilities, so they naturally sit closer to <code>low</code>.</li><li>Medium- and high-risk actions are still concentrated in the <code>public</code> official operations package and are not dropped into tenant-facing experience pages by default.</li><li>The early web-upload path used a lower default too often. This has already been unified to <code>medium</code>.</li></ul></article><article class="brand-card"><p class="brand-kicker">What To Do</p><h2>What to do when onboarding a new script</h2><ul class="brand-list"><li>Write <code>@risk low|medium|high</code> explicitly in the script header instead of leaving the decision to oral agreement.</li><li>If you are unsure, treat it as the higher level first instead of labeling it <code>low</code>.</li><li>Anything involving deployment, rollback, deletion, overwrite, or remote commands should not be treated like a normal utility script.</li></ul></article></section><section class="brand-card"><p class="brand-kicker">One Sentence</p><h2>One-sentence summary</h2><p class="brand-lead"> ExecFabric&#39;s script risk levels are not a scoring showpiece. They exist so the impact boundary is declared and governed before onboarding, manual confirmation, authorization, and audit. </p></section></div>',1)]))}const u=e(i,[["render",r]]);export{h as __pageData,u as default};
